		if (fullname==undefined){fullname=nickname;}
		if (aliases==undefined){aliases = "No known aliases";}
		//console.log("nickname",nickname);
		//console.log("fullname",fullname);
		//console.log("aliases",aliases);
		
		let className = this.props.className;
		if (className == undefined){className = "t13ne-geo-"+geonum;}
